using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class ChatTraining : TrainingContentBase
{
    public ChatTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Chat Overview",
            Slug = "chat-overview",
            Summary = "An overview of the built-in chat system including 1:1 direct messages, group rooms, real-time delivery via SignalR, and file/entity sharing.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 30,
            AppRoutes = """["/chat"]""",
            Tags = """["chat","communication"]""",
            ContentJson = """{"body":"## Chat Overview\n\nQB Engineer includes a built-in chat system for real-time internal communication. You can reach it from the sidebar or by clicking the chat icon in the header bar.\n\n### Accessing Chat\n\nChat opens as a slide-out panel from the right side of the screen. You can toggle it open or closed at any time without losing your place on the current page. The header chat icon also shows an unread message count badge so you always know when new messages arrive.\n\n### 1:1 Direct Messages\n\nThe primary chat mode is one-on-one direct messaging. Click the **New Message** button (+ icon) to open the user picker, search for a colleague by name, and start a conversation. Messages are delivered in real time via SignalR — no page refresh needed.\n\n### Group Rooms\n\nBeyond 1:1 conversations, chat supports group rooms. Group rooms allow multiple team members to collaborate in a shared thread. Room members see all messages posted to the room in real time.\n\n### Real-Time Delivery (SignalR)\n\nAll chat messages are delivered instantly through the ChatHub SignalR connection. When you send a message, the recipient sees it appear immediately without any polling or refresh. The connection is established automatically when you log in and reconnects with exponential backoff if interrupted.\n\n### File and Entity Sharing\n\nYou can share files and entity references (jobs, parts, purchase orders, etc.) directly within chat messages. Shared entities render as clickable links that open the relevant detail dialog.\n\n### Conversations List\n\nThe default chat view shows all your conversations sorted by most recent activity. Each conversation row displays:\n- **Avatar** with the other user's initials and color\n- **User name** in Last, First MI format\n- **Last message preview** (truncated to fit)\n- **Timestamp** — relative format (just now, 5m, 2h, 3d) or full date for older messages\n- **Unread badge** showing the count of unread messages\n\n### Message Thread\n\nOpening a conversation shows the full message thread with:\n- **Sender avatar** with initials and background color\n- **Message text** with preserved line breaks\n- **Timestamp** in HH:MM format\n- **Date separator lines** — Today, Yesterday, or the full date for older messages\n- **Visual distinction** for your own messages vs. received messages\n\n### Read Receipts\n\nWhen you open a conversation, all messages in that thread are automatically marked as read via `POST /api/v1/chat/messages/{otherUserId}/read`. The unread badge on the conversations list updates accordingly.","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Chat — Guided Tour",
            Slug = "chat-walkthrough",
            Summary = "A guided walkthrough of opening the chat panel, starting a new conversation, sending messages, and understanding unread indicators.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 30,
            AppRoutes = """["/chat"]""",
            Tags = """["chat","walkthrough"]""",
            ContentJson = """{"appRoute":"/dashboard","startButtonLabel":"Start Chat Tour","steps":[{"element":"[data-tour='chat-icon']","popover":{"title":"Open Chat","description":"Click the chat icon in the header to open the chat slide-out panel. The badge shows your unread message count. You can also navigate to /chat from the sidebar.","side":"bottom"}},{"element":"[data-tour='chat-conversations']","popover":{"title":"Conversations List","description":"This is your conversations list. Each row shows the other person's avatar, name, last message preview, timestamp, and unread count. Conversations are sorted by most recent activity.","side":"left"}},{"element":"[data-tour='chat-new-message']","popover":{"title":"Start a New Conversation","description":"Click the + icon to open the user picker. Search for a colleague by name to start a new 1:1 conversation. If you already have a conversation with that person, it opens the existing thread.","side":"left"}},{"element":"[data-tour='chat-message-input']","popover":{"title":"Compose a Message","description":"Type your message here. Press Enter to send, or Shift+Enter to add a new line. The send button is disabled when the input is empty or contains only whitespace.","side":"top"}},{"element":"[data-tour='chat-send-btn']","popover":{"title":"Send Message","description":"Click the send button or press Enter to send your message. Messages are delivered instantly via SignalR to the other user.","side":"top"}},{"element":"[data-tour='chat-unread-badge']","popover":{"title":"Unread Indicators","description":"Unread messages show a count badge on the conversation row. Opening a conversation automatically marks all its messages as read. The header chat icon badge updates in real time.","side":"left"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Chat Field Reference",
            Slug = "chat-field-reference",
            Summary = "Complete reference for every chat button, input field, keyboard shortcut, timestamp format, unread indicator, and API flow.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 30,
            AppRoutes = """["/chat"]""",
            Tags = """["chat","reference"]""",
            ContentJson = """{"title":"Chat Field Reference","groups":[{"heading":"Buttons","items":[{"label":"Open Chat (header icon)","value":"Toggles the chat slide-out panel open or closed. Shows unread message count badge. Available from any page."},{"label":"Close (icon: close)","value":"Closes the chat panel and returns to the underlying page."},{"label":"New Message (icon: add)","value":"Opens the user picker to start a new conversation. Search users by name to begin a 1:1 direct message."},{"label":"Back to Conversations (icon: arrow_back)","value":"Returns from the message thread or user picker view back to the conversations list."},{"label":"Send (icon: send, data-testid: chat-send-btn)","value":"Sends the composed message to the current conversation. Disabled when the input is empty or contains only whitespace. Messages are trimmed before sending."},{"label":"Cancel User Picker (icon: close)","value":"Closes the user picker and returns to the conversations list without starting a new conversation."}]},{"heading":"Input Fields","items":[{"label":"Message Input (data-testid: chat-message-input)","value":"Text input for composing messages. Supports multi-line input via Shift+Enter. Content is trimmed before sending — empty or whitespace-only messages are blocked."},{"label":"User Search","value":"Text input in the user picker for filtering available users. Filters in real time as you type. Shows matching users with their avatar, name, and role."}]},{"heading":"Keyboard Shortcuts","items":[{"label":"Enter","value":"Send the current message (when message input is focused and non-empty)"},{"label":"Shift+Enter","value":"Insert a new line in the message input without sending"},{"label":"Escape","value":"Close the chat panel"}]},{"heading":"Timestamp Formats","items":[{"label":"Conversation list — just now","value":"Message sent less than 1 minute ago"},{"label":"Conversation list — 5m, 2h, 3d","value":"Relative time for messages within the past week"},{"label":"Conversation list — full date","value":"MM/dd/yyyy format for messages older than one week"},{"label":"Message thread — time","value":"HH:MM format on each message bubble"},{"label":"Message thread — date separators","value":"'Today', 'Yesterday', or full date (MM/dd/yyyy) separating message groups by day"}]},{"heading":"Unread Indicators","items":[{"label":"Header chat icon badge","value":"Red badge showing total unread message count across all conversations. Updates in real time via SignalR."},{"label":"Conversation row badge","value":"Per-conversation unread count displayed next to the timestamp. Cleared when the conversation is opened."},{"label":"Mark as read","value":"Opening a conversation automatically calls POST /api/v1/chat/messages/{otherUserId}/read to mark all messages as read."}]},{"heading":"API Flow","items":[{"label":"GET /api/v1/chat/conversations","value":"Loads the conversations list with last message preview, unread count, and participant details."},{"label":"GET /api/v1/chat/messages/{otherUserId}","value":"Loads the full message history for a 1:1 conversation with the specified user."},{"label":"POST /api/v1/chat/messages","value":"Sends a new message. Body: { recipientId: number, content: string }. Returns the created message. Broadcasts via SignalR ChatHub."},{"label":"POST /api/v1/chat/messages/{otherUserId}/read","value":"Marks all messages from the specified user as read. Called automatically when opening a conversation."},{"label":"SignalR ChatHub","value":"Real-time message delivery. Connects on login, auto-reconnects with exponential backoff. Pushes new messages and read receipts to connected clients."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Chat Knowledge Check",
            Slug = "chat-quiz",
            Summary = "Test your knowledge of the chat system including messaging, keyboard shortcuts, unread indicators, and real-time delivery.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 30,
            AppRoutes = """["/training"]""",
            Tags = """["chat","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"chat1","text":"How do you open the chat panel from any page in the app?","options":[{"id":"a","text":"Navigate to /chat in the sidebar"},{"id":"b","text":"Click the chat icon in the header bar","isCorrect":true},{"id":"c","text":"Press Ctrl+C to toggle chat"},{"id":"d","text":"Open the notification panel and switch to the Messages tab"}],"explanation":"The chat icon in the header bar toggles the slide-out chat panel from any page. You can also navigate to /chat via the sidebar, but the header icon is available everywhere."},{"id":"chat2","text":"You want to send a message to a colleague you haven't messaged before. What do you do?","options":[{"id":"a","text":"Go to Admin > Users and find their profile"},{"id":"b","text":"Click the New Message button (+ icon) and search for their name in the user picker","isCorrect":true},{"id":"c","text":"Send them a notification and they will reply via chat"},{"id":"d","text":"Create a group room and add them to it"}],"explanation":"The New Message button opens the user picker where you can search for any user by name. Selecting a user starts a new 1:1 conversation or opens an existing one."},{"id":"chat3","text":"What keyboard shortcut sends a message in the chat input?","options":[{"id":"a","text":"Ctrl+Enter"},{"id":"b","text":"Shift+Enter"},{"id":"c","text":"Enter","isCorrect":true},{"id":"d","text":"Tab then Enter"}],"explanation":"Press Enter to send the current message. Use Shift+Enter if you need to insert a new line without sending."},{"id":"chat4","text":"How do you insert a line break in a chat message without sending it?","options":[{"id":"a","text":"Press Enter twice"},{"id":"b","text":"Press Shift+Enter","isCorrect":true},{"id":"c","text":"Type \\n in the message"},{"id":"d","text":"You cannot add line breaks in chat messages"}],"explanation":"Shift+Enter inserts a new line in the message input. Plain Enter sends the message immediately."},{"id":"chat5","text":"The send button is disabled. What is the most likely reason?","options":[{"id":"a","text":"You are not connected to the internet"},{"id":"b","text":"The message input is empty or contains only whitespace","isCorrect":true},{"id":"c","text":"The recipient has blocked you"},{"id":"d","text":"You have reached the daily message limit"}],"explanation":"The send button is disabled when the input is empty or contains only whitespace. Messages are trimmed before the check, so spaces-only input counts as empty."},{"id":"chat6","text":"How are chat messages delivered to the recipient in real time?","options":[{"id":"a","text":"The app polls the server every 5 seconds for new messages"},{"id":"b","text":"Push notifications are sent via the browser Notification API"},{"id":"c","text":"Messages are delivered instantly via the SignalR ChatHub connection","isCorrect":true},{"id":"d","text":"The recipient must refresh the page to see new messages"}],"explanation":"Chat uses SignalR (WebSocket connection) for real-time delivery. The ChatHub pushes messages instantly to connected clients without polling or page refresh."},{"id":"chat7","text":"You see a red badge with '3' on the header chat icon. What does this mean?","options":[{"id":"a","text":"3 users are currently online"},{"id":"b","text":"You have 3 total conversations"},{"id":"c","text":"You have 3 unread messages across all conversations","isCorrect":true},{"id":"d","text":"3 group rooms have new activity"}],"explanation":"The header chat icon badge shows the total unread message count across all conversations. It updates in real time as new messages arrive or conversations are read."},{"id":"chat8","text":"How are messages in a conversation marked as read?","options":[{"id":"a","text":"You must click a 'Mark as Read' button on each message"},{"id":"b","text":"Opening the conversation automatically marks all its messages as read","isCorrect":true},{"id":"c","text":"Messages are marked as read after 10 seconds of viewing"},{"id":"d","text":"You must scroll to the bottom of the conversation"}],"explanation":"Opening a conversation automatically calls the read API endpoint to mark all messages from that user as read. The unread badge updates immediately."},{"id":"chat9","text":"In the conversations list, a message timestamp shows '3d'. What does this mean?","options":[{"id":"a","text":"The message was sent at 3:00 AM on the current day"},{"id":"b","text":"The message will be deleted in 3 days"},{"id":"c","text":"The last message in this conversation was sent 3 days ago","isCorrect":true},{"id":"d","text":"There are 3 unread messages in this conversation"}],"explanation":"Timestamps in the conversation list use relative format: 'just now' for under a minute, '5m'/'2h'/'3d' for recent messages, and full date (MM/dd/yyyy) for messages older than a week."},{"id":"chat10","text":"What date separator format is used in message threads for messages from two weeks ago?","options":[{"id":"a","text":"'Last Week'"},{"id":"b","text":"The day name (e.g., 'Monday')"},{"id":"c","text":"The full date in MM/dd/yyyy format","isCorrect":true},{"id":"d","text":"No separator is shown for older messages"}],"explanation":"Message threads show date separators between message groups. The labels are 'Today', 'Yesterday', or the full date in MM/dd/yyyy format for all other days."},{"id":"chat11","text":"You click the back arrow (arrow_back) while viewing a message thread. Where does it take you?","options":[{"id":"a","text":"To the previous page you were on before opening chat"},{"id":"b","text":"Back to the conversations list","isCorrect":true},{"id":"c","text":"To the user's profile"},{"id":"d","text":"It closes the chat panel entirely"}],"explanation":"The back arrow navigates from the message thread or user picker view back to the conversations list. To close the entire chat panel, use the close (X) button."},{"id":"chat12","text":"What happens if the SignalR connection is lost while you are chatting?","options":[{"id":"a","text":"All unsent messages are permanently lost"},{"id":"b","text":"The app switches to polling mode automatically"},{"id":"c","text":"The connection automatically reconnects with exponential backoff","isCorrect":true},{"id":"d","text":"You must log out and log back in to restore the connection"}],"explanation":"SignalR connections automatically reconnect with exponential backoff when interrupted. A connection banner appears showing the reconnecting/disconnected status until the connection is restored."}]}"""
        });

        Log.Information("Seeded Chat training modules");
    }
}
